    }
}

using Microsoft.AspNetCore.Components;
using sv_180d60a92d864a2381b36bb1c4d2d00b.Models;
using sv_180d60a92d864a2381b36bb1c4d2d00b.Services;

namespace sv_180d60a92d864a2381b36bb1c4d2d00b.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles bridging the session ID from
/// the static prerender phase (where HttpContext is available) to the
/// interactive phase (where it is not) via PersistentComponentState.
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateStore Store { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Nav { get; set; } = default!;

    protected string SessionId { get; private set; } = "";
    protected WizardData Data { get; private set; } = new();

    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", SessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            // Prerender phase — HttpContext is available
            var session = HttpContextAccessor.HttpContext?.Session;
            if (session is not null)
            {
                session.SetString("_init", "1"); // ensure session cookie is issued
                SessionId = session.Id;
            }
        }
        else
        {
            // Interactive phase — restore the persisted session ID
            SessionId = restored ?? "";
        }

        if (!string.IsNullOrEmpty(SessionId))
        {
            Data = Store.GetOrCreate(SessionId);
        }

        LoadData();
    }

    /// <summary>Populate local form fields from <see cref="Data"/>.</summary>
    protected abstract void LoadData();

    /// <summary>Copy local form fields back into <see cref="Data"/>.</summary>
    protected abstract void SaveData();

    protected void SaveAndNavigate(string nextUrl, int completedStep)
    {
        SaveData();
        Data.CompletedSteps.Add(completedStep);
        Nav.NavigateTo(nextUrl);
    }

    protected void NavigateBack(string url)
    {
        SaveData();
        Nav.NavigateTo(url);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

