@inherits LayoutComponentBase
@layout MainLayout
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_180d60a92d864a2381b36bb1c4d2d00b.Services.WizardStateStore Store
@inject NavigationManager Nav

<div class="wizard-header mb-4">
    <h3>Job Application</h3>
    <p class="text-muted">Step @_currentStep of @Steps.Length</p>

    <div class="wizard-steps d-flex gap-1 mb-3">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var step = Steps[i];
            var stepNum = i + 1;
            var isCurrent = stepNum == _currentStep;
            var isCompleted = _completedSteps.Contains(stepNum);
            <a href="@step.Url"
               class="wizard-step text-decoration-none d-flex align-items-center gap-2 px-3 py-2 rounded
                      @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-dark")">
                <span class="badge @(isCurrent ? "bg-white text-primary" : isCompleted ? "bg-white text-success" : "bg-secondary text-white") rounded-circle">
                    @(isCompleted ? "✓" : stepNum)
                </span>
                <span>@step.Label</span>
            </a>
        }
    </div>
</div>

@Body

@code {
    private record StepInfo(string Url, string Label);

    internal static readonly StepInfo[] Steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private int _currentStep = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        var index = Array.FindIndex(Steps, s =>
            path.Equals(s.Url, StringComparison.OrdinalIgnoreCase));
        _currentStep = index >= 0 ? index + 1 : 1;

        // Layout is static SSR — HttpContext is always available here
        var session = HttpContextAccessor.HttpContext?.Session;
        if (session is not null)
        {
            session.SetString("_init", "1");
            var data = Store.GetOrCreate(session.Id);
            _completedSteps = data.CompletedSteps;
        }
    }
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout
@inherits sv_180d60a92d864a2381b36bb1c4d2d00b.Components.Pages.Apply.WizardStepBase

<PageTitle>Personal Info – Application</PageTitle>

<h4>Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="_name" placeholder="Jane Doe" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="_email" placeholder="jane@example.com" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string _name = "";
    private string _email = "";

    protected override void LoadData()
    {
        _name = Data.PersonalInfo.Name;
        _email = Data.PersonalInfo.Email;
    }

    protected override void SaveData()
    {
        Data.PersonalInfo.Name = _name;
        Data.PersonalInfo.Email = _email;
    }

    private void Next() => SaveAndNavigate("/apply/experience", completedStep: 1);
}

@page "/apply/experience"
@rendermode InteractiveServer
@layout WizardLayout
@inherits sv_180d60a92d864a2381b36bb1c4d2d00b.Components.Pages.Apply.WizardStepBase

<PageTitle>Experience – Application</PageTitle>

<h4>Work Experience</h4>

@if (_jobs.Count == 0)
{
    <p class="text-muted">No job history entries yet. Click "Add Job" to begin.</p>
}

@for (int i = 0; i < _jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <strong>Job @(index + 1)</strong>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="_jobs[index].Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Title</label>
                <input class="form-control" @bind="_jobs[index].Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="_jobs[index].Duration" placeholder="e.g. 2 years" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private List<sv_180d60a92d864a2381b36bb1c4d2d00b.Models.JobEntry> _jobs = [];

    protected override void LoadData()
    {
        // Deep-copy so edits don't mutate the store until Save
        _jobs = Data.Experience.Jobs
            .Select(j => new sv_180d60a92d864a2381b36bb1c4d2d00b.Models.JobEntry
            {
                Company = j.Company,
                Title = j.Title,
                Duration = j.Duration
            })
            .ToList();
    }

    protected override void SaveData()
    {
        Data.Experience.Jobs = _jobs
            .Select(j => new sv_180d60a92d864a2381b36bb1c4d2d00b.Models.JobEntry
            {
                Company = j.Company,
                Title = j.Title,
                Duration = j.Duration
            })
            .ToList();
    }

    private void AddJob() => _jobs.Add(new());
    private void RemoveJob(int index) => _jobs.RemoveAt(index);
    private void Next() => SaveAndNavigate("/apply/references", completedStep: 2);
    private void Back() => NavigateBack("/apply/personal-info");
}

@page "/apply/references"
