@inherits LayoutComponentBase
@layout MainLayout
@inject IHttpContextAccessor HttpContextAccessor
@inject sv_180d60a92d864a2381b36bb1c4d2d00b.Services.WizardStateStore Store
@inject NavigationManager Nav

<div class="wizard-header mb-4">
    <h3>Job Application</h3>
    <p class="text-muted">Step @_currentStep of @Steps.Length</p>

    <div class="wizard-steps d-flex gap-1 mb-3">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var step = Steps[i];
            var stepNum = i + 1;
            var isCurrent = stepNum == _currentStep;
            var isCompleted = _completedSteps.Contains(stepNum);
            <a href="@step.Url"
               class="wizard-step text-decoration-none d-flex align-items-center gap-2 px-3 py-2 rounded
                      @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-dark")">
                <span class="badge @(isCurrent ? "bg-white text-primary" : isCompleted ? "bg-white text-success" : "bg-secondary text-white") rounded-circle">
                    @(isCompleted ? "✓" : stepNum)
                </span>
                <span>@step.Label</span>
            </a>
        }
    </div>
</div>

@Body

@code {
    private record StepInfo(string Url, string Label);

    internal static readonly StepInfo[] Steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private int _currentStep = 1;
    private HashSet<int> _completedSteps = [];

    protected override void OnInitialized()
    {
        var path = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
        var index = Array.FindIndex(Steps, s =>
            path.Equals(s.Url, StringComparison.OrdinalIgnoreCase));
        _currentStep = index >= 0 ? index + 1 : 1;

        // Layout is static SSR — HttpContext is always available here
        var session = HttpContextAccessor.HttpContext?.Session;
        if (session is not null)
        {
            session.SetString("_init", "1");
            var data = Store.GetOrCreate(session.Id);
            _completedSteps = data.CompletedSteps;
        }
    }
}

